def compute_top_similar(target_norm, texts, topn=20):
    sims = []
    for i, orig, norm in texts:
        sim, cr, f1 = combined_similarity(target_norm, norm)
        sims.append((sim, cr, f1, i, orig))
    sims.sort(reverse=True)
    return sims[:topn]

# Define combined_similarity as earlier
def lcs(a, b):
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        ai = a[i-1]
        for j in range(1, m+1):
            temp = dp[j]
            if ai == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = dp[j] if dp[j] >= dp[j-1] else dp[j-1]
            prev = temp
    return dp[m]

def char_ratio(a, b):
    a2 = ''.join(a.split())
    b2 = ''.join(b.split())
    if not a2 or not b2:
        return 0.0
    l = lcs(a2, b2)
    return (2*l) / (len(a2) + len(b2))

def token_f1(a, b):
    ta = a.split()
    tb = b.split()
    if not ta or not tb:
        return 0.0
    from collections import Counter
    ca, cb = Counter(ta), Counter(tb)
    inter = sum((ca & cb).values())
    precision = inter / len(tb)
    recall = inter / len(ta)
    if precision + recall == 0:
        return 0.0
    return 2*precision*recall/(precision+recall)

def combined_similarity(a, b):
    cr = char_ratio(a, b)
    f1 = token_f1(a, b)
    return (cr + f1) / 2.0, cr, f1

